fn build_greeting(names: &Vec<String>) -> String {
    let mut result = String::new();
    result.push_str("Hello ");
    let mut first = true;
    for name in names {
        if !first {
            result.push_str(", ");
        }
        result.push_str(name);
        first = false;
    }
    result.push_str("!");
    result
}
